<?php
require __DIR__ . '/config.php'; require_login();
$q = trim($_GET['q'] ?? ''); $status = $_GET['status'] ?? '';
$sql = 'SELECT * FROM items WHERE 1=1'; $params = [];
if ($q !== '') { $sql .= ' AND (item_no LIKE ? OR name LIKE ? OR location LIKE ? OR category LIKE ?)'; $like = "%$q%"; $params = [$like,$like,$like,$like]; }
if ($status !== '') { $sql .= ' AND status = ?'; $params[] = $status; }
$sql .= ' ORDER BY found_at DESC, id DESC LIMIT 100';
$stmt = db()->prepare($sql); $stmt->execute($params); $items = $stmt->fetchAll();
$counts = db()->query("SELECT COUNT(*) total, SUM(status='Depoda') storage, SUM(status='Eşleşme bekliyor') waiting, SUM(status='Teslim edildi') delivered FROM items")->fetch();
?>
